inline unsigned rc_icon_lookup(const RcIcon* a, int n, unsigned rid) {
    int lo = 0, hi = n - 1;
    while (lo <= hi) { int mid = (lo + hi) >> 1; unsigned m = a[mid].recast_id;
        if (m == rid) return a[mid].icon_id; if (m < rid) lo = mid + 1; else hi = mid - 1; }
    return 0; }
inline unsigned ja_recast_icon(unsigned rid)    { return rc_icon_lookup(JA_RC_ICON, JA_RC_ICON_N, rid); }
inline unsigned spell_recast_icon(unsigned rid) { return rc_icon_lookup(SP_RC_ICON, SP_RC_ICON_N, rid); }
